// src/cli/commands/migrate.ts
async function runMigrate(action) {
  logger.blank();
  if (detectPrisma()) {
    await migratePrisma(action);
    return;
  }
  if (detectMongoose()) {
    await migrateMongoose(action);
    return;
  }
  logger.error("No adapter detected. Run npx permifyjs init first.");
  process.exit(1);
}
async function migratePrisma(action) {
  const spinner = ora("Running Prisma migration...").start();
  try {
    const commands = {
      migrate: ["prisma", "migrate", "dev", "--name", "add_permifyjs"],
      rollback: ["prisma", "migrate", "reset", "--force"],
      fresh: ["prisma", "migrate", "reset", "--force"],
      status: ["prisma", "migrate", "status"]
    };
    const [cmd, ...args] = commands[action];
    await execa(cmd, args, { stdio: "inherit", cwd: process.cwd() });
    spinner.succeed("Prisma migration complete");
  } catch (err) {
    spinner.fail("Prisma migration failed");
    logger.error(String(err));
    process.exit(1);
  }
}
async function migrateMongoose(action) {
  const spinner = ora("Setting up MongoDB collections...").start();
  try {
    if (action === "status") {
      spinner.info("Mongoose creates collections automatically on first write");
      return;
    }
    spinner.succeed("MongoDB collections will be created on first write");
    logger.info("Make sure registerPermifyModels() is called in your app");
  } catch (err) {
    spinner.fail("MongoDB setup failed");
    logger.error(String(err));
  }
}

// src/cli/commands/role.ts
async function runRoleCommand(action, opts) {
  logger.blank();
  logger.info(`role:${action} \u2014 connect this to your resolver to execute`);
  logger.step("Use auth.assignRole(), auth.removeRole() in your app code");
  logger.step("Or seed directly via your DB client");
  logger.blank();
  switch (action) {
    case "create":
      logger.info(`Creating role: ${opts.name}`);
      break;
    case "list":
      logger.info("Listing all roles...");
      break;
    case "assign":
      logger.info(`Assigning role ${opts.role} to ${opts.modelType}:${opts.modelId}`);
      break;
    case "remove":
      logger.info(`Removing role ${opts.role} from ${opts.modelType}:${opts.modelId}`);
      break;
  }
}

// src/cli/commands/permission.ts
async function runPermissionCommand(action, opts) {
  logger.blank();
  switch (action) {
    case "create":
      logger.info(`Creating permission: ${opts.name}`);
      break;
    case "list":
      logger.info("Listing all permissions...");
      break;
    case "assign":
      logger.info(`Assigning permission ${opts.permission} to role ${opts.role}`);
      break;
  }
  logger.step("Use auth.assignPermissionToRole() in your app code");
  logger.step("Or seed directly via your DB client");
  logger.blank();
}

// src/cli/commands/user.ts
async function runUserCommand(action, opts) {
  logger.blank();
  switch (action) {
    case "roles":
      logger.info(`Roles for ${opts.modelType}:${opts.modelId}`);
      logger.step("Use auth.hasRole() or resolver.getRoles() in your app");
      break;
    case "permissions":
      logger.info(`Permissions for ${opts.modelType}:${opts.modelId}`);
      logger.step("Use auth.getAllPermissions() in your app");
      break;
  }
  logger.blank();
}

// src/cli/bin.ts
var program2 = new Command();
program2.name("permifyjs").description("permifyjs \u2014 framework agnostic RBAC for Node.js").version("0.1.0");
program2.command("init").description("Set up permifyjs in your project").action(runInit);
program2.command("migrate").description("Run permifyjs migrations").action(() => runMigrate("migrate"));
program2.command("migrate:rollback").description("Rollback last migration").action(() => runMigrate("rollback"));
program2.command("migrate:fresh").description("Drop all tables and re-run migrations").action(() => runMigrate("fresh"));
program2.command("migrate:status").description("Show migration status").action(() => runMigrate("status"));
program2.command("role:create <name>").description("Create a new role").action((name) => runRoleCommand("create", { name }));
program2.command("role:list").description("List all roles").action(() => runRoleCommand("list", {}));
program2.command("role:assign").description("Assign a role to a model").requiredOption("--model-id <id>", "Model ID").option("--model-type <type>", "Model type", "User").requiredOption("--role <role>", "Role name").action((opts) => runRoleCommand("assign", opts));
program2.command("role:remove").description("Remove a role from a model").requiredOption("--model-id <id>", "Model ID").option("--model-type <type>", "Model type", "User").requiredOption("--role <role>", "Role name").action((opts) => runRoleCommand("remove", opts));
program2.command("permission:create <name>").description("Create a new permission").action((name) => runPermissionCommand("create", { name }));
program2.command("permission:list").description("List all permissions").action(() => runPermissionCommand("list", {}));
program2.command("permission:assign").description("Assign a permission to a role").requiredOption("--role <role>", "Role name").requiredOption("--permission <permission>", "Permission name").action((opts) => runPermissionCommand("assign", opts));
program2.command("user:roles").description("List roles for a model").requiredOption("--model-id <id>", "Model ID").option("--model-type <type>", "Model type", "User").action((opts) => runUserCommand("roles", opts));
program2.command("user:permissions").description("List permissions for a model").requiredOption("--model-id <id>", "Model ID").option("--model-type <type>", "Model type", "User").action((opts) => runUserCommand("permissions", opts));
program2.parse(process.argv);
